request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?table ?tableType ?tableName ?child ?childType ?childName WHERE {
  ?table vocab:NamedElement_name ?tableName .
  FILTER(CONTAINS(LCASE(STR(?tableName)), LCASE("Wavefront%20Calibration%20Lookup%20Table")))
  ?table rdf:type ?tableType .

  OPTIONAL { ?table vocab:Element_ownedElement+ ?child . ?child rdf:type ?childType . }
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25
